// SummerCollection.js - COMPLETE WITH CART INTEGRATION
import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import "../styles/Dress.css";
import dress1 from "../assets/images/auri_dress1.jpg";
import dress2 from "../assets/images/auri_dress2.jpg";
import dress3 from "../assets/images/auri_dress3.jpg";


const summerItems = [
  { 
    id: 1, 
    title: "Tropical Breeze Dress", 
    price: "$89", 
    img: dress1 ,
    category: "dress",
    style: "elegant",
    description: "A beautiful flowy dress perfect for summer evenings. Made with lightweight, breathable fabric that keeps you cool all day long.",
    sizes: ["XS", "S", "M", "L", "XL"],
    colors: ["Coral", "Sky Blue", "Mint Green"],
    material: "100% Organic Cotton",
    care: "Machine wash cold, tumble dry low"
  },
  { 
    id: 2, 
    title: "Sunset Glow Top", 
    price: "$45", 
    img: dress2, 
    category: "top",
    style: "casual",
    description: "Comfortable and stylish top with a relaxed fit. Perfect for casual outings or beach days.",
    sizes: ["S", "M", "L", "XL"],
    colors: ["Sunset Orange", "Cream", "Dusty Pink"],
    material: "Linen Blend",
    care: "Hand wash recommended, lay flat to dry"
  },
  { 
    id: 3, 
    title: "Ocean Wave Skirt", 
    price: "$65", 
    img: dress3, 
    category: "skirt",
    style: "elegant",
    description: "Elegant midi skirt with a beautiful wave pattern. Flowy and comfortable for any occasion.",
    sizes: ["XS", "S", "M", "L"],
    colors: ["Navy Blue", "White", "Seafoam Green"],
    material: "Silk Blend",
    care: "Dry clean only"
  },
];

const SummerCollection = () => {
  const navigate = useNavigate();
  const { addToCart, isInCart } = useCart();

  const [selectedStyle, setSelectedStyle] = useState("all");
  const [selectedItem, setSelectedItem] = useState(null);
  const [selectedSize, setSelectedSize] = useState("");
  const [selectedColor, setSelectedColor] = useState("");

  const styleCategories = ["all", "casual", "elegant"];

  const filteredItems = selectedStyle === "all" 
    ? summerItems 
    : summerItems.filter(item => item.style === selectedStyle);

  const openQuickView = (item) => {
    setSelectedItem(item);
    setSelectedSize("");
    setSelectedColor("");
  };

  const closeQuickView = () => {
    setSelectedItem(null);
  };

  const handleAddToCart = () => {
    if (!selectedSize) {
      alert("Please select a size");
      return;
    }
    if (!selectedColor) {
      alert("Please select a color");
      return;
    }

    // Add to cart with all necessary information
    addToCart({
      ...selectedItem,
      selectedSize,
      selectedColor
    });

    alert(`Added ${selectedItem.title} (${selectedSize}, ${selectedColor}) to cart!`);
    closeQuickView();
  };

  // Add direct add to cart function for the main "Add to Cart" buttons
  const handleDirectAddToCart = (item) => {
    // For direct add, use default size and color
    const defaultSize = item.sizes[0];
    const defaultColor = item.colors[0];

    addToCart({
      ...item,
      selectedSize: defaultSize,
      selectedColor: defaultColor
    });

    alert(`Added ${item.title} to cart!`);
  };

  // Check if item is already in cart for quick view
  const isItemInCart = (item, size, color) => {
    return isInCart(item.id, size, color);
  };

  return (
    <section className="summer-collection">
      <div className="container">
        {/* Header Section */}
        <div className="collection-header">
          <motion.button 
            className="back-button"
            onClick={() => navigate(-1)}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            ← Back to All Collections
          </motion.button>

          <div className="header-content">
            <motion.h1
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
            >
              Dress Collection
            </motion.h1>

            {/* Style Categories */}
            <motion.div 
              className="style-categories"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.1 }}
            >
              {styleCategories.map((style) => (
                <button
                  key={style}
                  className={`style-btn ${selectedStyle === style ? 'active' : ''}`}
                  onClick={() => setSelectedStyle(style)}
                >
                  {style.charAt(0).toUpperCase() + style.slice(1)}
                </button>
              ))}
            </motion.div>

            <motion.p
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.2 }}
            >
              Embrace the sunshine with our exclusive summer styles. Light, breathable, and perfect for warm days.
            </motion.p>
          </div>
        </div>

        {/* Collection Grid */}
        <motion.div 
          className="summer-grid"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.8, delay: 0.4 }}
        >
          {filteredItems.map((item) => (
            <motion.div
              key={item.id}
              className="summer-card"
              whileHover={{ y: -10 }}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
            >
              <div className="card-image">
                <img src={item.img} alt={item.title} />
                <div className="card-overlay">
                  <motion.button 
                    className="quick-view-btn"
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    onClick={() => openQuickView(item)}
                  >
                    Quick View
                  </motion.button>
                </div>
                <div className="category-badge">
                  {item.category}
                </div>
                <div className="style-badge">
                  {item.style}
                </div>
              </div>
              <div className="card-content">
                <h3>{item.title}</h3>
                <p className="price">{item.price}</p>
                <motion.button 
                  className="add-to-cart-btn"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                  onClick={() => handleDirectAddToCart(item)}
                >
                  Add to Cart
                </motion.button>
              </div>
            </motion.div>
          ))}
        </motion.div>

        {/* Additional Summer Info */}
        <motion.div 
          className="summer-info"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.8 }}
        >
          <div className="info-card">
            <h3>☀️ Perfect for Summer</h3>
            <p>Our summer collection features lightweight fabrics, breathable materials, and vibrant colors designed to keep you cool and stylish all season long.</p>
          </div>
          <div className="info-card">
            <h3>🌊 Beach to Street</h3>
            <p>Versatile pieces that transition seamlessly from beach days to evening outings. Mix and match to create your perfect summer wardrobe.</p>
          </div>
          <div className="info-card">
            <h3>🌿 Sustainable Style</h3>
            <p>Made with eco-friendly materials and ethical production practices. Look good while doing good for the planet.</p>
          </div>
        </motion.div>
      </div>

      {/* Quick View Modal */}
      <AnimatePresence>
        {selectedItem && (
          <motion.div
            className="sc-modal-overlay"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={closeQuickView}
          >
            <motion.div
              className="sc-quick-view-modal"
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.8, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
            >
              <button className="sc-close-button" onClick={closeQuickView}>
                ×
              </button>

              <div className="sc-modal-content">
                <div className="sc-modal-image-section">
                  <div className="sc-image-container">
                    <img src={selectedItem.img} alt={selectedItem.title} />
                    <div className="sc-image-overlay">
                      <div className="sc-image-badges">
                        <span className="sc-category-badge">{selectedItem.category}</span>
                        <span className="sc-style-badge">{selectedItem.style}</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="sc-modal-details">
                  <div className="sc-detail-header">
                    <h2>{selectedItem.title}</h2>
                    <p className="sc-modal-price">{selectedItem.price}</p>
                  </div>

                  <p className="sc-modal-description">{selectedItem.description}</p>

                  <div className="sc-selection-sections">
                    <div className="sc-detail-section">
                      <h4>Select Size</h4>
                      <div className="sc-size-options">
                        {selectedItem.sizes.map((size) => (
                          <button
                            key={size}
                            className={`sc-size-btn ${selectedSize === size ? 'selected' : ''}`}
                            onClick={() => setSelectedSize(size)}
                          >
                            {size}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div className="sc-detail-section">
                      <h4>Select Color</h4>
                      <div className="sc-color-options">
                        {selectedItem.colors.map((color) => (
                          <button
                            key={color}
                            className={`sc-color-btn ${selectedColor === color ? 'selected' : ''}`}
                            onClick={() => setSelectedColor(color)}
                          >
                            <span className="sc-color-dot"></span>
                            {color}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  {/* Product Info Card */}
                  <div className="sc-product-info-card">
                    <h4>Product Details</h4>
                    <div className="sc-info-grid">
                      <div className="sc-info-item">
                        <div className="sc-info-icon">🧵</div>
                        <div className="sc-info-content">
                          <div className="sc-info-label">Material</div>
                          <div className="sc-info-value">{selectedItem.material}</div>
                        </div>
                      </div>
                      <div className="sc-info-item">
                        <div className="sc-info-icon">👕</div>
                        <div className="sc-info-content">
                          <div className="sc-info-label">Care Instructions</div>
                          <div className="sc-info-value">{selectedItem.care}</div>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="sc-action-buttons">
                    <motion.button 
                      className="sc-modal-add-to-cart"
                      onClick={handleAddToCart}
                      whileHover={{ scale: 1.02 }}
                      whileTap={{ scale: 0.98 }}
                      disabled={!selectedSize || !selectedColor}
                    >
                      <span className="sc-cart-icon">🛒</span>
                      {isItemInCart(selectedItem, selectedSize, selectedColor) 
                        ? 'Added to Cart' 
                        : `Add to Cart - ${selectedItem.price}`}
                    </motion.button>
                  </div>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
};

export default SummerCollection;
